// === STEP 1: Decide fetch method (Browserless headless Chrome OR simple HTTP) ===
// If BROWSERLESS_TOKEN is set in n8n env or passed in body, use headless Chrome.
// Otherwise fall back to HTTP Request.

const url = $input.first().json.body.url;
const keyword = ($input.first().json.body.keyword || '').trim();
const browserlessToken = $input.first().json.body.browserless_token || process.env.BROWSERLESS_TOKEN || '';

return [{ json: { url, keyword, browserlessToken, useBrowserless: browserlessToken.length > 0 } }];

// === ViraSEO ADVANCED PAGE INSPECTOR — Full SEO Espionage ===
// Works with both Browserless (rendered HTML) and simple HTTP (raw HTML).
// Extracts 25+ SEO signals + strengths/weaknesses + keyword prominence.

const input = $input.first().json;
const html = typeof input === 'string' ? input : (input.body || input.data || '');
const url = $('Prepare').first().json.url;
const keyword = ($('Prepare').first().json.keyword || '').toLowerCase().trim();

function strip(s) { return (s||'').replace(/<[^>]+>/g, ' ').replace(/&[a-z]+;/g, ' ').replace(/\s+/g, ' ').trim(); }

// === METADATA (always in <head>, even for JS pages) ===
let title = ''; const tm = html.match(/<title[^>]*>(.*?)<\/title>/si); if (tm) title = strip(tm[1]);
let metaDesc = ''; let md = html.match(/<meta[^>]+name\s*=\s*["']description["'][^>]*content\s*=\s*["']([^"']*)["']/i); if (md) metaDesc = md[1]; if (!metaDesc) { md = html.match(/<meta[^>]+content\s*=\s*["']([^"']*)["'][^>]*name\s*=\s*["']description["']/i); if (md) metaDesc = md[1]; }
let ogTitle = ''; md = html.match(/<meta[^>]+property\s*=\s*["']og:title["'][^>]*content\s*=\s*["']([^"']*)["']/i); if (md) ogTitle = md[1];
let ogDesc = ''; md = html.match(/<meta[^>]+property\s*=\s*["']og:description["'][^>]*content\s*=\s*["']([^"']*)["']/i); if (md) ogDesc = md[1];
let ogImage = ''; md = html.match(/<meta[^>]+property\s*=\s*["']og:image["'][^>]*content\s*=\s*["']([^"']*)["']/i); if (md) ogImage = md[1];
let canonical = ''; md = html.match(/<link[^>]+rel\s*=\s*["']canonical["'][^>]*href\s*=\s*["']([^"']+)["']/i); if (md) canonical = md[1];
let robots = 'index, follow'; md = html.match(/<meta[^>]+name\s*=\s*["']robots["'][^>]*content\s*=\s*["']([^"']*)["']/i); if (md) robots = md[1];
let lang = ''; md = html.match(/<html[^>]+lang\s*=\s*["']([^"']+)["']/i); if (md) lang = md[1];

// === SCHEMA ===
const schemaTypes = [...new Set((html.match(/"@type"\s*:\s*"([^"]+)"/gi)||[]).map(s => { const m2 = s.match(/"([^"]+)"$/); return m2?m2[1]:''; }).filter(Boolean))];

// === CONTENT EXTRACTION ===
let content = html.replace(/<(script|style|svg|template|iframe|noscript)[^>]*>[\s\S]*?<\/\1>/gi, ' ');
let body = content; const bm = content.match(/<body[^>]*>([\s\S]*)<\/body>/i); if (bm) body = bm[1];
body = body.replace(/<(nav|footer|header|aside|form|sidebar)[^>]*>[\s\S]*?<\/\1>/gi, ' ');

let mainContent = '';
const selectors = [/<main[^>]*>([\s\S]*?)<\/main>/i, /<article[^>]*>([\s\S]*?)<\/article>/i, /<div[^>]*class\s*=\s*["'][^"']*entry-content[^"']*["'][^>]*>([\s\S]*?)<\/div>/i, /<div[^>]*class\s*=\s*["'][^"']*post-content[^"']*["'][^>]*>([\s\S]*?)<\/div>/i, /<div[^>]*class\s*=\s*["'][^"']*product-description[^"']*["'][^>]*>([\s\S]*?)<\/div>/i, /<div[^>]*id\s*=\s*["']content["'][^>]*>([\s\S]*?)<\/div>/i];
for (const sel of selectors) { const sm = body.match(sel); if (sm && strip(sm[1]).split(/\s+/).length >= 30) { mainContent = sm[1]; break; } }
if (!mainContent) { const hm = body.match(/<h[12]\b[^>]*>([\s\S]*)/i); if (hm) mainContent = hm[1]; }
if (!mainContent) mainContent = body;

const text = strip(mainContent);
const words = text.split(/\s+/).filter(w => w.length > 0);
const wordCount = words.length;

// === HEADINGS ===
const h1s = (html.match(/<h1[^>]*>(.*?)<\/h1>/gi)||[]).map(h => strip(h)).filter(Boolean);
const h2s = (html.match(/<h2[^>]*>(.*?)<\/h2>/gi)||[]).map(h => strip(h)).filter(Boolean);
const h3s = (html.match(/<h3[^>]*>(.*?)<\/h3>/gi)||[]).map(h => strip(h)).filter(Boolean);

// === IMAGES ===
const imgs = html.match(/<img\b[^>]*>/gi)||[]; const imagesCount = imgs.length;
let noAlt = 0; imgs.forEach(t => { if (!/\balt\s*=\s*["'][^"']+["']/i.test(t)) noAlt++; });

// === LINKS ===
const host = (() => { try { return new URL(url).hostname; } catch(e) { return ''; } })();
const anchors = html.match(/<a\s[^>]*href\s*=\s*["']([^"'#]+)["'][^>]*>/gi)||[];
let intLinks = 0, extLinks = 0;
anchors.forEach(a => { const hm = a.match(/href\s*=\s*["']([^"'#]+)["']/i); if (!hm) return; const h = hm[1]; if (h.startsWith('/')||h.includes(host)) intLinks++; else if (h.startsWith('http')) extLinks++; });

// === MISC METRICS ===
const paragraphs = (html.match(/<p\b[^>]*>/gi)||[]).length;
const tables = (html.match(/<table\b/gi)||[]).length;
const videos = (html.match(/<(video|iframe)[^>]*(youtube|vimeo|aparat|mp4|embed)/gi)||[]).length;
const hasFaq = /سوالات متداول|پرسش.*متداول|FAQ|faq-section|schema.*FAQPage|itemtype.*FAQPage/i.test(html);
const hasToc = /table.of.content|فهرست مطالب|جدول محتوا|lwptoc|ez-toc|toc-/i.test(html);
const hasForm = /<form\b/i.test(html);
const hasBreadcrumb = /breadcrumb|BreadcrumbList/i.test(html);

// === TOP KEYWORDS ===
const stops = ['و','در','به','از','که','این','را','با','است','برای','آن','یک','تا','هم','ها','یا','شده','می','بر','اما','هر','نیز','the','is','a','of','to','in','for','on','with'];
const wList = text.toLowerCase().split(/[\s\u200C\u200B,.;:!?()\[\]\/\\"']+/).filter(w => w.length > 2 && !stops.includes(w) && !/^\d+$/.test(w));
const freq = {}; wList.forEach(w => freq[w]=(freq[w]||0)+1);
const topKw = Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,12).map(([word,count])=>({word,count}));
// Bigrams
const bigrams = {}; for (let i=0;i<wList.length-1;i++) { const bg=wList[i]+' '+wList[i+1]; bigrams[bg]=(bigrams[bg]||0)+1; }
const topBigrams = Object.entries(bigrams).sort((a,b)=>b[1]-a[1]).slice(0,5).filter(([_,c])=>c>=2).map(([word,count])=>({word,count}));
const allTopKw = [...topKw, ...topBigrams].sort((a,b)=>b.count-a.count).slice(0,12);

// === KEYWORD ANALYSIS ===
let kwAnalysis = {};
if (keyword) {
  const kl = keyword; const tl = title.toLowerCase(); const ml = metaDesc.toLowerCase(); const ul = url.toLowerCase();
  const inTitle = tl.includes(kl)?1:0; const inH1 = h1s.some(h=>h.toLowerCase().includes(kl))?1:0;
  const inH2 = h2s.some(h=>h.toLowerCase().includes(kl))?1:0; const inMeta = ml.includes(kl)?1:0; const inUrl = ul.includes(kl)?1:0;
  const kwCount = (text.toLowerCase().split(kl).length-1); const density = wordCount>0?Math.round((kwCount/wordCount)*10000)/100:0;
  const prominence = Math.min(100, (inTitle?25:0)+(inH1?20:0)+(inH2?10:0)+(inMeta?15:0)+(inUrl?15:0)+Math.min(15,Math.round(density*5)));
  // First occurrence position (earlier = better)
  const firstPos = text.toLowerCase().indexOf(kl);
  const firstPosPercent = firstPos >= 0 && text.length > 0 ? Math.round((firstPos / text.length) * 100) : -1;
  kwAnalysis = { in_title:inTitle, in_h1:inH1, in_h2:inH2, in_meta:inMeta, in_url:inUrl, density, prominence, count:kwCount, first_position_percent: firstPosPercent };
}

// === READING LEVEL ===
const sents = text.split(/[.!?؟]+/).filter(s=>s.trim().length>10);
const avgSent = sents.length>0?Math.round(words.length/sents.length):0;

// === CONTENT TYPE ===
let contentType = '-';
if (/product|shop|store|cart|woocommerce/i.test(url)||/"@type"\s*:\s*"Product"/i.test(html)) contentType='product';
else if (/blog|article|mag|news|post|wiki/i.test(url)||/"@type"\s*:\s*"(Article|BlogPosting)"/i.test(html)) contentType='article';
else if (/service|khadamat/i.test(url)) contentType='service';
else if (wordCount>300) contentType='article';

// === SECTION BREAKDOWN ===
const sectionWords = [];
const parts = mainContent.split(/<h2\b[^>]*>/i);
for (let i=1; i<parts.length && i<=10; i++) {
  const hm2 = parts[i].match(/^(.*?)<\/h2>/si);
  const heading = hm2 ? strip(hm2[1]) : 'بخش '+i;
  const rest = hm2 ? parts[i].slice(hm2[0].length) : parts[i];
  const cleaned = rest.replace(/<h[1-6]\b.*$/si,'');
  const wds = strip(cleaned).split(/\s+/).filter(Boolean).length;
  sectionWords.push({heading, words: wds});
}

// === STRENGTHS & WEAKNESSES ===
const strengths = []; const weaknesses = [];
if (wordCount>=1500) strengths.push('محتوای جامع و طولانی ('+wordCount+' کلمه)');
else if (wordCount>=800) strengths.push('طول محتوا مناسب ('+wordCount+' کلمه)');
else weaknesses.push('محتوا کوتاه ('+wordCount+' کلمه). رقبای قوی ۱۵۰۰+ دارند.');
if (h2s.length>=4) strengths.push('ساختار هدینگ عالی ('+h2s.length+' H2)'); else if (h2s.length<2) weaknesses.push('هدینگ H2 خیلی کم ('+h2s.length+'). ساختار ضعیف.');
if (imagesCount>=4) strengths.push('تصاویر متنوع ('+imagesCount+')'); else if (imagesCount<2) weaknesses.push('تصاویر خیلی کم ('+imagesCount+').');
if (noAlt>0) weaknesses.push(noAlt+' تصویر بدون alt.');
if (tables>0) strengths.push('جدول دارد ('+tables+'). محتوای ساختاریافته.'); else weaknesses.push('جدول ندارد.');
if (hasFaq) strengths.push('بخش FAQ (فرصت Featured Snippet).'); else weaknesses.push('FAQ ندارد.');
if (videos>0) strengths.push('ویدیو ('+videos+' عدد).');
if (hasToc) strengths.push('فهرست مطالب (Table of Contents) دارد.');
if (hasBreadcrumb) strengths.push('Breadcrumb (مسیر ناوبری) دارد.');
if (intLinks>=5) strengths.push('لینک داخلی قوی ('+intLinks+')'); else if (intLinks<3) weaknesses.push('لینک داخلی کم ('+intLinks+').');
if (extLinks>=1&&extLinks<=5) strengths.push('استناد خارجی ('+extLinks+')'); else if (extLinks===0) weaknesses.push('هیچ استنادی ندارد.');
else if (extLinks>10) weaknesses.push('لینک خارجی زیاد ('+extLinks+'). نشت لینک.');
if (schemaTypes.length>0) strengths.push('Schema: '+schemaTypes.join(', ')); else weaknesses.push('Schema ندارد. Rich Snippet از دست رفته.');
if (metaDesc&&metaDesc.length>=120&&metaDesc.length<=160) strengths.push('متا بهینه ('+metaDesc.length+' کاراکتر).');
else if (!metaDesc) weaknesses.push('متا ندارد!'); else if (metaDesc.length<100) weaknesses.push('متا کوتاه ('+metaDesc.length+').');
if (title.length>=30&&title.length<=65) strengths.push('عنوان بهینه.'); else if (title.length>65) weaknesses.push('عنوان بلند ('+title.length+'). کوتاه می‌شود.');
if (keyword) {
  if (kwAnalysis.in_title) strengths.push('کلمه در عنوان ✓'); else weaknesses.push('کلمه در عنوان نیست!');
  if (kwAnalysis.in_h1) strengths.push('کلمه در H1 ✓'); else weaknesses.push('کلمه در H1 نیست.');
  if (kwAnalysis.density>=0.5&&kwAnalysis.density<=2.5) strengths.push('تراکم مناسب ('+kwAnalysis.density+'%)'); 
  else if (kwAnalysis.density<0.5) weaknesses.push('تراکم خیلی کم ('+kwAnalysis.density+'%).');
  else weaknesses.push('تراکم زیاد ('+kwAnalysis.density+'%). خطر اسپم!');
  if (kwAnalysis.first_position_percent>=0&&kwAnalysis.first_position_percent<=15) strengths.push('کلمه در ۱۵٪ ابتدای محتوا (عالی).');
  else if (kwAnalysis.first_position_percent>30) weaknesses.push('اولین ظهور کلمه دیر است ('+kwAnalysis.first_position_percent+'٪ محتوا).');
}

// === SCORE ===
let score = 0;
score += Math.min(30, Math.round(wordCount/50));
score += Math.min(15, h2s.length*3);
score += Math.min(10, imagesCount*2);
score += (h1s.length>=1)?8:0;
score += (tables>0)?5:0;
score += (hasFaq)?10:0;
score += (schemaTypes.length>0)?8:0;
score += (extLinks>=1)?4:0;
score += (metaDesc.length>=100)?5:0;
score += (hasToc)?3:0;
score += (hasBreadcrumb)?2:0;
score = Math.min(100, score);

return [{ json: {
  url, word_count: wordCount, word_count_fa: wordCount.toLocaleString('fa-IR'),
  h1: h1s.length, h2: h2s.length, h3: h3s.length,
  h1_texts: h1s.slice(0,3), h2_texts: h2s.slice(0,15), h3_texts: h3s.slice(0,8),
  images: imagesCount, images_no_alt: noAlt,
  internal_links: intLinks, external_links: extLinks,
  title, meta_desc: metaDesc, og_title: ogTitle, og_description: ogDesc, og_image: ogImage,
  canonical_url: canonical, robots_meta: robots, language: lang,
  schema: schemaTypes, paragraphs, tables, videos,
  has_faq: hasFaq?1:0, has_video: videos>0?1:0, has_table: tables>0?1:0,
  has_toc: hasToc?1:0, has_breadcrumb: hasBreadcrumb?1:0, has_form: hasForm?1:0,
  content_type: contentType, reading_level: avgSent,
  keyword_density: kwAnalysis.density||0,
  top_keywords: allTopKw, word_count_score: score,
  keyword_analysis: kwAnalysis,
  response_time: 0,
  strengths, weaknesses,
  section_words: sectionWords,
  note: wordCount<50&&html.length>10000 ? 'صفحه JS-rendered است. Browserless برای تحلیل دقیق‌تر توصیه می‌شود.' : ''
}}];
